// ================= CARS MODULE =================

function loadCars() {
    fetch(`${API_URL}/cars`)
        .then(r => r.json())
        .then(showCars)
        .catch(() => showToast('Error loading cars', 'error'));
}

function showCars(cars) {
    const container = document.querySelector('[data-screen="cars-list"] .content');
    if (!container) return;

    container.innerHTML = '';

    if (!cars.length) {
        container.innerHTML = `<p>No cars available</p>`;
        return;
    }

    cars.forEach(car => {
        const div = document.createElement('div');
        div.className = 'car-item';
        div.innerHTML = `
            <b>${car.brand}</b> ${car.model} - ${car.price} EGP
            <button data-delete="${car.id}">Delete</button>
        `;
        container.appendChild(div);
    });

    setupCarEvents();
}

function setupCarEvents() {
    document.querySelectorAll('[data-delete]').forEach(btn => {
        btn.onclick = () => deleteCar(btn.dataset.delete);
    });
}

function deleteCar(id) {
    fetch(`${API_URL}/cars/${id}`, { method: 'DELETE' })
        .then(() => {
            showToast('Car deleted', 'success');
            loadCars();
        });
}

function addCar() {
    const brand = document.getElementById('add-car-brand').value.trim();
    const model = document.getElementById('add-car-model').value.trim();
    const price = document.getElementById('add-car-price').value.trim();

    if (!brand || !model || !price) {
        showToast('Please fill all fields', 'error');
        return;
    }

    fetch(`${API_URL}/cars`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ brand, model, price })
    })
    .then(() => {
        showToast('Car added successfully', 'success');
        loadCars();
        showScreen('cars-list');
    });
}

function initCarsModule() {
    const saveBtn = document.getElementById('save-car');
    if (saveBtn) saveBtn.onclick = addCar;
}

// init when DOM ready
document.addEventListener('DOMContentLoaded', initCarsModule);

// expose globally if needed
window.loadCars = loadCars;
